import{_ as e,o as i,c as r,ag as o}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Capacidad de Corriente (Ampacidad)","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/fundamentals/current-capacity.md","filePath":"es/cables/fundamentals/current-capacity.md"}'),l={name:"es/cables/fundamentals/current-capacity.md"};function n(c,a,t,d,s,m){return i(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="capacidad-de-corriente-ampacidad" tabindex="-1">Capacidad de Corriente (Ampacidad) <a class="header-anchor" href="#capacidad-de-corriente-ampacidad" aria-label="Permalink to &quot;Capacidad de Corriente (Ampacidad)&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>La capacidad de corriente, comúnmente conocida como ampacidad, es la cantidad máxima de corriente eléctrica que un conductor puede transportar de forma continua sin exceder su temperatura permitida.</p><p>La ampacidad es uno de los parámetros más críticos en el diseño y selección de cables, ya que afecta directamente la seguridad, el desempeño y la vida útil del conductor.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El objetivo de definir la capacidad de corriente es asegurar que el cable opere dentro de límites térmicos seguros.</p><p>Si un conductor transporta más corriente que su ampacidad:</p><ul><li>La temperatura aumenta</li><li>El aislamiento puede degradarse</li><li>El riesgo de falla o incendio se incrementa</li></ul><p>Una correcta selección de ampacidad garantiza una operación segura y confiable del sistema eléctrico.</p><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>Cuando la corriente fluye a través de un conductor, se genera calor debido a la resistencia eléctrica.</p><p>La cantidad de calor generado depende de:</p><ul><li>Magnitud de la corriente</li><li>Resistencia del conductor</li><li>Duración del flujo de corriente</li></ul><p>Al mismo tiempo, el cable disipa calor hacia su entorno.</p><p>La ampacidad se determina por el equilibrio entre:</p><ul><li>El calor generado dentro del conductor</li><li>El calor disipado hacia el ambiente</li></ul><p>Si el calor generado supera la disipación, la temperatura del cable excederá límites seguros.</p><hr><h2 id="factores-que-afectan-la-capacidad-de-corriente" tabindex="-1">Factores que Afectan la Capacidad de Corriente <a class="header-anchor" href="#factores-que-afectan-la-capacidad-de-corriente" aria-label="Permalink to &quot;Factores que Afectan la Capacidad de Corriente&quot;">​</a></h2><h3 id="material-del-conductor" tabindex="-1">Material del Conductor <a class="header-anchor" href="#material-del-conductor" aria-label="Permalink to &quot;Material del Conductor&quot;">​</a></h3><ul><li>El cobre tiene menor resistencia → mayor ampacidad para el mismo tamaño</li><li>El aluminio tiene mayor resistencia → menor ampacidad (requiere mayor sección)</li></ul><hr><h3 id="tamano-del-conductor-area-de-seccion" tabindex="-1">Tamaño del Conductor (Área de Sección) <a class="header-anchor" href="#tamano-del-conductor-area-de-seccion" aria-label="Permalink to &quot;Tamaño del Conductor (Área de Sección)&quot;">​</a></h3><ul><li>Conductores más grandes transportan más corriente</li><li>Conductores más pequeños se calientan más rápido</li></ul><hr><h3 id="tipo-de-aislamiento" tabindex="-1">Tipo de Aislamiento <a class="header-anchor" href="#tipo-de-aislamiento" aria-label="Permalink to &quot;Tipo de Aislamiento&quot;">​</a></h3><p>Diferentes materiales de aislamiento tienen distintos límites de temperatura:</p><ul><li>PVC: típicamente hasta 70–90°C</li><li>XLPE: típicamente hasta 90°C o más</li></ul><p>Mayores temperaturas permitidas → mayor ampacidad.</p><hr><h3 id="temperatura-ambiente" tabindex="-1">Temperatura Ambiente <a class="header-anchor" href="#temperatura-ambiente" aria-label="Permalink to &quot;Temperatura Ambiente&quot;">​</a></h3><ul><li>Temperaturas altas reducen la capacidad de disipación</li><li>La ampacidad debe reducirse en ambientes calientes</li></ul><hr><h3 id="metodo-de-instalacion" tabindex="-1">Método de Instalación <a class="header-anchor" href="#metodo-de-instalacion" aria-label="Permalink to &quot;Método de Instalación&quot;">​</a></h3><p>La disipación de calor varía según la instalación:</p><ul><li>Aire libre → mejor enfriamiento → mayor ampacidad</li><li>Tubería (conduit) → enfriamiento limitado → menor ampacidad</li><li>Charolas con agrupamiento → menor disipación</li></ul><hr><h3 id="agrupamiento-de-cables" tabindex="-1">Agrupamiento de Cables <a class="header-anchor" href="#agrupamiento-de-cables" aria-label="Permalink to &quot;Agrupamiento de Cables&quot;">​</a></h3><ul><li>Múltiples cables cercanos generan calor combinado</li><li>Requiere aplicar factores de corrección (derating)</li></ul><hr><h3 id="ciclo-de-trabajo" tabindex="-1">Ciclo de Trabajo <a class="header-anchor" href="#ciclo-de-trabajo" aria-label="Permalink to &quot;Ciclo de Trabajo&quot;">​</a></h3><ul><li>Cargas continuas generan más calor</li><li>Cargas intermitentes pueden permitir mayor corriente efectiva</li></ul><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La ampacidad se utiliza en:</p><ul><li>Selección de tamaño de cable para motores y equipos</li><li>Diseño de sistemas de distribución eléctrica</li><li>Cumplimiento de normas eléctricas</li><li>Evaluación del desempeño térmico en instalaciones</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al evaluar la capacidad de corriente:</p><ul><li>Considerar condiciones reales de instalación, no ideales</li><li>Aplicar factores de corrección cuando sea necesario</li><li>Verificar los límites térmicos del aislamiento</li><li>Utilizar normas aplicables (NEC, IEC) como referencia</li><li>Considerar incrementos futuros de carga</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>Los valores de ampacidad en tablas asumen condiciones específicas; no deben usarse sin ajuste.</li><li>Los cables subdimensionados son una causa común de sobrecalentamiento y fallas.</li><li>Un sobredimensionamiento conservador incrementa el costo, pero mejora el margen térmico.</li><li>El agrupamiento y la temperatura ambiente suelen subestimarse, pero tienen gran impacto.</li><li>En entornos industriales, las condiciones reales rara vez son ideales; siempre se deben ajustar los cálculos.</li></ul>',55)])])}const h=e(l,[["render",n]]);export{p as __pageData,h as default};
